/// <reference types="cypress" />
// ***********************************************
// This example commands.ts shows you how to
// create various custom commands and overwrite
// existing commands.
//
// For more comprehensive examples of custom
// commands please read more here:
// https://on.cypress.io/custom-commands
// ***********************************************
//
//
// -- This is a parent command --
// Cypress.Commands.add('login', (email, password) => { ... })
//
//
// -- This is a child command --
// Cypress.Commands.add('drag', { prevSubject: 'element'}, (subject, options) => { ... })
//
//
// -- This is a dual command --
// Cypress.Commands.add('dismiss', { prevSubject: 'optional'}, (subject, options) => { ... })
//
//
// -- This will overwrite an existing command --
// Cypress.Commands.overwrite('visit', (originalFn, url, options) => { ... })
//
// declare global {
//   namespace Cypress {
//     interface Chainable {
//       login(email: string, password: string): Chainable<void>
//       drag(subject: string, options?: Partial<TypeOptions>): Chainable<Element>
//       dismiss(subject: string, options?: Partial<TypeOptions>): Chainable<Element>
//       visit(originalFn: CommandOriginalFn, url: string, options: Partial<VisitOptions>): Chainable<Element>
//     }
//   }
// }

declare namespace Cypress {
  interface Chainable {
    login(username: string): Chainable<void>;
    logout(): Chainable<void>;
    openWorkspace(workspace: string): Chainable<void>;
    createWorkspace(workspace: string): Chainable<void>;
    deleteWorkspace(workspace: string): Chainable<void>;
    openChannel(channel: string): Chainable<void>;
    createChannel(channel: string): Chainable<void>;
    deleteChannel(channel: string): Chainable<void>;
    createPost(post: string): Chainable<void>;
    getPost(post: string): Chainable<JQuery<Element>>;
    replyToPost(reply: string): Chainable<void>;
    reactToPost(reaction: string): Chainable<void>;
  }
}

/*
 * This file contains the necessary custom commands to interact with your
 * application.  These commands should only do exactly what they say they do and
 * should only assume what the comments say they should assume.  These commands
 * can be used within your own tests and will be used by the machine grading
 * system to test your application.  It is therefore incredibly important you do
 * not change the behavior of these commands or the assumptions they make.
 *
 * Each command is likely to only be 2-3 lines of code that calls chained Cypress
 * commands.  If you find yourself writing a lot of code in a command, you may
 * want to ask for help or reconsider the structure of your application.
 *
 * Note that Cypress cannot "get" or "find" custom elements. However, as long as
 * the shadow DOM is created as "open", it can search within the shadow DOM. If
 * you need to return a custom element, you can "find" an element within the
 * shadow DOM and use ".parent()" as needed to return the custom element.
 */

/**
 * Login using given username.
 *
 * Assumes that no one is currently logged in.
 *
 * @param username Username to login with.
 */
Cypress.Commands.add("login", (username: string) => {
  cy.get("#usernameInput").clear().type(username);
  cy.get("#loginForm").submit();
  // Wait for app to become visible after login
  cy.get("#appContainer", { timeout: 5000 }).should("not.have.css", "display", "none");
});

/**
 * Logout the currently logged in user.
 *
 * Assumes that a user is currently logged in.
 */
Cypress.Commands.add("logout", () => {
  cy.get("#logoutBtn").click();
  cy.get("#loginContainer").should("be.visible");
});

/**
 * Open a workspace.
 *
 * Assumes that someone is logged in and that the workspace exists.
 *
 * @param workspace Name of the workspace to open.
 */
Cypress.Commands.add("openWorkspace", (workspace: string) => {
  cy.contains("li", workspace).click();
  cy.get("#workspaceName").should("contain", workspace);
});

/**
 * Create a workspace.
 *
 * Assumes that someone is logged in and that the workspace does not exist.
 *
 * @param workspace Name of the workspace to create.
 */
Cypress.Commands.add("createWorkspace", (workspace: string) => {
  cy.get("#newWorkspaceBtn").click();
  cy.get("#modalInput").type(workspace);
  cy.get("#modalConfirmBtn").click();
  cy.get("#modal").should("not.be.visible");
  cy.contains(workspace).should("exist");
});

/**
 * Delete a workspace.
 *
 * Assumes that someone is logged in and that the workspace exists.
 *
 * @param workspace Name of the workspace to delete.
 */
Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
  cy.contains("li", workspace).click();
  cy.get("#deleteWorkspaceBtn").click();
  cy.on("window:confirm", () => true);
});

/**
 * Open a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 *
 * @param channel Name of the channel to open.
 */
Cypress.Commands.add("openChannel", (channel: string) => {
  cy.get("#channelList").contains(channel).click();
  cy.get("#channelName").should("contain", channel);
});

/**
 * Create a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * does not exist in that workspace.
 *
 * @param channel Name of the channel to create.
 */
Cypress.Commands.add("createChannel", (channel: string) => {
  cy.get("#newChannelBtn").click();
  cy.get("#modalInput").type(channel);
  cy.get("#modalConfirmBtn").click();
  cy.get("#modal").should("not.be.visible");
  cy.get("#channelList").contains(channel).should("exist");
});

/**
 * Delete a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 *
 * @param channel Name of the channel to delete.
 */
Cypress.Commands.add("deleteChannel", (channel: string) => {
  cy.get("#channelList").contains(channel).click();
  cy.get("#deleteChannelBtn").click();
  cy.on("window:confirm", () => true);
});

/**
 * Create a post.
 *
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 *
 * @param post Text of the post to create.
 */
Cypress.Commands.add("createPost", (post: string) => {
  cy.get("#postInput").type(post);
  cy.get("#sendPostBtn").click();
});

/**
 * Get a post.
 *
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 * Also can assume the text only appears in a single post in the channel.
 * The given searchText may not be the full text of the post, but the post should
 * contain the searchText in its entirety.
 *
 * @param searchText Text that appears in the post to get.
 * @returns The post element that contains the searchText.  This element will
 *          be passed to the replyToPost and reactToPost commands, so should
 *          be the enclosing post element that allows those actions.
 */
Cypress.Commands.add(
  "getPost",
  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
    return cy.get(".post").contains(searchText).closest(".post");
  }
);

/**
 * Reply to a post.
 *
 * Assumes that someone is logged in, a workspace is open, a channel is open, and
 * that the provided post exists and came from the "getPost" command.
 *
 * @param subject The post to reply to (from getPost).
 * @param reply Text of the reply to create.
 */
Cypress.Commands.add(
  "replyToPost",
  { prevSubject: true },
  (subject, reply: string) => {
    cy.wrap(subject).find(".reply-btn").click();
    cy.wrap(subject).find(".reply-input").type(reply);
    cy.wrap(subject).find(".send-reply-btn").click();
  }
);

/**
 * React to a post.
 *
 * Assumes that someone is logged in, a workspace is open, a channel is open,
 * and that the provided post exists and came from the "getPost" command.
 *
 * @param subject The post to react to (from getPost).
 * @param reaction The reaction to react with (should be one of ":smile:",
 *                 ":frown:", ":like:", or ":celebrate:").
 */
Cypress.Commands.add(
  "reactToPost",
  { prevSubject: true },
  (subject, reaction: string) => {
    cy.wrap(subject).find(".post-actions").contains(reaction).click();
  }
);

import { slog } from "./slog";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

// ============================================================================
// Types and Constants
// ============================================================================

interface Workspace {
  name: string;
  [key: string]: unknown;
}

interface Channel {
  name: string;
  [key: string]: unknown;
}

interface Post {
  msg: string;
  parent?: string;
  reactions?: Record<string, string[]>;
  extensions?: Record<string, unknown>;
  [key: string]: unknown;
}

interface AuthResponse {
  token: string;
  [key: string]: unknown;
}

// Use PARCEL_PUBLIC_ prefixed variables for Parcel to inject them
// Fallback to default values if not set
const DB_HOST = process.env.PARCEL_PUBLIC_DATABASE_HOST || process.env.DATABASE_HOST || "http://localhost:4318";
const DB_PATH = process.env.PARCEL_PUBLIC_DATABASE_PATH || process.env.DATABASE_PATH || "/v1/m3ssag1n8/";
const AUTH_PATH = process.env.PARCEL_PUBLIC_AUTH_PATH || process.env.AUTH_PATH || "/v1/auth/";

// ============================================================================
// Global State
// ============================================================================

let currentUser: string | null = null;
let authToken: string | null = null;
let currentWorkspace: string | null = null;
let currentChannel: string | null = null;

// Emoji mapping
const emojiMap: Record<string, string> = {
  ":smile:": "😊",
  ":frown:": "☹️",
  ":like:": "👍",
  ":celebrate:": "🎉",
};

// UI Elements - declare them but don't initialize yet
let loginContainer: HTMLElement;
let appContainer: HTMLElement;
let loginForm: HTMLElement;
let usernameInput: HTMLInputElement;
let currentUsernameEl: HTMLElement;
let logoutBtn: HTMLElement;
let workspaceList: HTMLElement;
let newWorkspaceBtn: HTMLElement;
let workspaceView: HTMLElement;
let noWorkspaceSelected: HTMLElement;
let workspaceName: HTMLElement;
let deleteWorkspaceBtn: HTMLElement;
let channelList: HTMLElement;
let newChannelBtn: HTMLElement;
let channelView: HTMLElement;
let noChannelSelected: HTMLElement;
let channelName: HTMLElement;
let deleteChannelBtn: HTMLElement;
let postsContainer: HTMLElement;
let postInput: HTMLTextAreaElement;
let sendPostBtn: HTMLElement;
let modal: HTMLElement;
let modalOverlay: HTMLElement;
let modalTitle: HTMLElement;
let modalInput: HTMLInputElement;
let modalConfirmBtn: HTMLElement;
let modalCancelBtn: HTMLElement;
let modalError: HTMLElement;
let errorModal: HTMLElement;
let errorMessage: HTMLElement;
let errorCloseBtn: HTMLElement;

// ============================================================================
// API Calls
// ============================================================================

async function apiCall(
  method: string,
  path: string,
  body?: unknown
): Promise<Response> {
  const url = `${DB_HOST}${path}`;
  const headers: Record<string, string> = {};

  if (authToken) {
    headers["Authorization"] = `Bearer ${authToken}`;
  }

  const options: RequestInit = {
    method,
    headers,
  };

  if (body !== undefined) {
    headers["Content-Type"] = "application/json";
    options.body = JSON.stringify(body);
  }

  return fetch(url, options);
}

async function authenticate(username: string): Promise<boolean> {
  try {
    const response = await fetch(`${DB_HOST}${AUTH_PATH}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username }),
    });

    if (!response.ok) {
      return false;
    }

    const data = (await response.json()) as AuthResponse;
    authToken = data.token;
    currentUser = username;
    return true;
  } catch (error) {
    console.error("Authentication failed:", error);
    return false;
  }
}

async function logout(): Promise<boolean> {
  try {
    const response = await fetch(`${DB_HOST}${AUTH_PATH}`, {
      method: "DELETE",
      headers: {
        Authorization: `Bearer ${authToken}`,
      },
    });

    authToken = null;
    currentUser = null;
    currentWorkspace = null;
    currentChannel = null;
    return response.ok || response.status === 204;
  } catch (error) {
    console.error("Logout failed:", error);
    return false;
  }
}

async function getWorkspaces(): Promise<Workspace[]> {
  try {
    const response = await apiCall("GET", DB_PATH);
    if (!response.ok) {
      return [];
    }

    const data = (await response.json()) as Record<string, Workspace>;
    const workspaces: Workspace[] = [];

    for (const [name, workspace] of Object.entries(data)) {
      if (
        name !== "collections" &&
        typeof workspace === "object" &&
        workspace !== null
      ) {
        workspaces.push({ ...workspace, name });
      }
    }

    return workspaces.sort((a, b) => a.name.localeCompare(b.name));
  } catch (error) {
    console.error("Failed to get workspaces:", error);
    return [];
  }
}

async function createWorkspace(name: string): Promise<boolean> {
  try {
    const encodedName = encodeURIComponent(name);
    const response = await apiCall("PUT", `${DB_PATH}${encodedName}`, {});

    if (!response.ok) {
      return false;
    }

    // Create channels collection
    const collResponse = await apiCall(
      "PUT",
      `${DB_PATH}${encodedName}/channels/`,
      {}
    );

    return collResponse.ok;
  } catch (error) {
    console.error("Failed to create workspace:", error);
    return false;
  }
}

async function deleteWorkspace(name: string): Promise<boolean> {
  try {
    const encodedName = encodeURIComponent(name);
    const response = await apiCall("DELETE", `${DB_PATH}${encodedName}`);
    return response.ok || response.status === 204;
  } catch (error) {
    console.error("Failed to delete workspace:", error);
    return false;
  }
}

async function getChannels(workspace: string): Promise<Channel[]> {
  try {
    const encodedWs = encodeURIComponent(workspace);
    const response = await apiCall("GET", `${DB_PATH}${encodedWs}/channels/`);

    if (!response.ok) {
      return [];
    }

    const data = (await response.json()) as Record<string, Channel>;
    const channels: Channel[] = [];

    for (const [name, channel] of Object.entries(data)) {
      if (
        name !== "collections" &&
        typeof channel === "object" &&
        channel !== null
      ) {
        channels.push({ ...channel, name });
      }
    }

    return channels.sort((a, b) => a.name.localeCompare(b.name));
  } catch (error) {
    console.error("Failed to get channels:", error);
    return [];
  }
}

async function createChannel(workspace: string, name: string): Promise<boolean> {
  try {
    const encodedWs = encodeURIComponent(workspace);
    const encodedCh = encodeURIComponent(name);
    const response = await apiCall(
      "PUT",
      `${DB_PATH}${encodedWs}/channels/${encodedCh}`,
      {}
    );

    if (!response.ok) {
      return false;
    }

    // Create posts collection
    const postResponse = await apiCall(
      "PUT",
      `${DB_PATH}${encodedWs}/channels/${encodedCh}/posts/`,
      {}
    );

    return postResponse.ok;
  } catch (error) {
    console.error("Failed to create channel:", error);
    return false;
  }
}

async function deleteChannel(workspace: string, name: string): Promise<boolean> {
  try {
    const encodedWs = encodeURIComponent(workspace);
    const encodedCh = encodeURIComponent(name);
    const response = await apiCall(
      "DELETE",
      `${DB_PATH}${encodedWs}/channels/${encodedCh}`
    );
    return response.ok || response.status === 204;
  } catch (error) {
    console.error("Failed to delete channel:", error);
    return false;
  }
}

async function getPosts(
  workspace: string,
  channel: string
): Promise<Array<{ path: string; doc: Post }>> {
  try {
    const encodedWs = encodeURIComponent(workspace);
    const encodedCh = encodeURIComponent(channel);
    const response = await apiCall(
      "GET",
      `${DB_PATH}${encodedWs}/channels/${encodedCh}/posts/`
    );

    if (!response.ok) {
      return [];
    }

    const data = (await response.json()) as Record<string, unknown>;
    const posts: Array<{ path: string; doc: Post }> = [];

    for (const [name, doc] of Object.entries(data)) {
      if (
        name !== "collections" &&
        typeof doc === "object" &&
        doc !== null &&
        "msg" in doc
      ) {
        const path = `${encodedWs}/channels/${encodedCh}/posts/${name}`;
        posts.push({ path, doc: doc as Post });
      }
    }

    return posts;
  } catch (error) {
    console.error("Failed to get posts:", error);
    return [];
  }
}

async function createPost(
  workspace: string,
  channel: string,
  msg: string,
  parent: string = ""
): Promise<string | null> {
  try {
    const encodedWs = encodeURIComponent(workspace);
    const encodedCh = encodeURIComponent(channel);
    const response = await apiCall(
      "POST",
      `${DB_PATH}${encodedWs}/channels/${encodedCh}/posts/`,
      { msg, parent }
    );

    if (!response.ok) {
      return null;
    }

    const data = (await response.json()) as Record<string, unknown>;
    return data.uri as string | null;
  } catch (error) {
    console.error("Failed to create post:", error);
    return null;
  }
}

async function updatePostReactions(
  postPath: string,
  reactions: Record<string, string[]>
): Promise<boolean> {
  try {
    const response = await apiCall("PATCH", `${DB_PATH}${postPath}`, [
      {
        op: "ObjectAdd",
        path: "/reactions",
        value: reactions,
      },
    ]);

    return response.ok;
  } catch (error) {
    console.error("Failed to update reactions:", error);
    return false;
  }
}

// ============================================================================
// UI Updates
// ============================================================================

function showLoginUI(): void {
  loginContainer.style.display = "flex";
  appContainer.style.display = "none";
}

function showAppUI(): void {
  loginContainer.style.display = "none";
  appContainer.style.display = "flex";
  currentUsernameEl.textContent = currentUser || "";
}

function showModal(
  title: string,
  callback: (value: string) => Promise<void>
): void {
  modalTitle.textContent = title;
  modalInput.value = "";
  modalError.textContent = "";
  modalInput.focus();

  const handleConfirm = async (e: Event): Promise<void> => {
    e.preventDefault();
    const value = modalInput.value.trim();

    if (!value) {
      modalError.textContent = "Please enter a name";
      return;
    }

    try {
      await callback(value);
      hideModal();
    } catch (error) {
      modalError.textContent = (error as Error).message || "An error occurred";
    }
  };

  const handleCancel = (): void => {
    hideModal();
  };

  modalConfirmBtn.onclick = (e) => handleConfirm(e);
  modalCancelBtn.onclick = handleCancel;

  modal.style.display = "block";
  modalOverlay.style.display = "block";
}

function hideModal(): void {
  modal.style.display = "none";
  modalOverlay.style.display = "none";
  modalConfirmBtn.onclick = null;
  modalCancelBtn.onclick = null;
}

function showError(message: string): void {
  errorMessage.textContent = message;
  errorModal.style.display = "block";
  modalOverlay.style.display = "block";

  errorCloseBtn.onclick = (): void => {
    errorModal.style.display = "none";
    modalOverlay.style.display = "none";
    errorCloseBtn.onclick = null;
  };
}

async function refreshWorkspaceList(): Promise<void> {
  const workspaces = await getWorkspaces();
  workspaceList.innerHTML = "";

  for (const ws of workspaces) {
    const li = document.createElement("li");
    li.className = currentWorkspace === ws.name ? "active" : "";
    li.innerHTML = `
      <span class="ws-name">${escapeHtml(ws.name)}</span>
    `;
    li.onclick = (): void => {
      openWorkspace(ws.name);
    };
    workspaceList.appendChild(li);
  }
}

async function openWorkspace(name: string): Promise<void> {
  currentWorkspace = name;
  currentChannel = null;
  workspaceName.textContent = name;
  workspaceView.style.display = "flex";
  noWorkspaceSelected.style.display = "none";
  noChannelSelected.style.display = "block";
  channelView.style.display = "none";

  await refreshWorkspaceList();
  await refreshChannelList();
}

async function refreshChannelList(): Promise<void> {
  if (!currentWorkspace) return;

  const channels = await getChannels(currentWorkspace);
  channelList.innerHTML = "";

  for (const ch of channels) {
    const li = document.createElement("li");
    li.className = currentChannel === ch.name ? "active" : "";
    li.innerHTML = `
      <span class="ch-name">${escapeHtml(ch.name)}</span>
    `;
    li.onclick = (): void => {
      openChannel(ch.name);
    };
    channelList.appendChild(li);
  }
}

async function openChannel(name: string): Promise<void> {
  if (!currentWorkspace) return;

  currentChannel = name;
  channelName.textContent = name;
  noChannelSelected.style.display = "none";
  channelView.style.display = "flex";

  await refreshChannelList();
  await displayPosts();
}

async function displayPosts(): Promise<void> {
  if (!currentWorkspace || !currentChannel) return;

  const posts = await getPosts(currentWorkspace, currentChannel);
  postsContainer.innerHTML = "";

  // Group posts into threads
  const topLevelPosts: Map<string, Array<{ path: string; doc: Post }>> =
    new Map();
  const postsByPath: Map<string, { path: string; doc: Post }> = new Map();

  for (const post of posts) {
    postsByPath.set(post.path, post);
  }

  for (const post of posts) {
    const parent = post.doc.parent || "";
    if (!parent || parent === "") {
      if (!topLevelPosts.has("")) {
        topLevelPosts.set("", []);
      }
      topLevelPosts.get("")!.push(post);
    }
  }

  // Display posts
  for (const post of posts) {
    const parent = post.doc.parent || "";
    if (!parent || parent === "") {
      displayPost(post, posts);
    }
  }
}

function displayPost(
  post: { path: string; doc: Post },
  allPosts: Array<{ path: string; doc: Post }>
): void {
  const postEl = document.createElement("div");
  postEl.className = "post";
  postEl.setAttribute("data-path", post.path);

  const author = extractAuthorFromPath(post.path);
  const time = new Date().toLocaleTimeString();

  let formattedContent = formatContent(post.doc.msg);

  const header = document.createElement("div");
  header.className = "post-header";
  header.innerHTML = `
    <span class="post-author">${escapeHtml(author)}</span>
    <span class="post-time">${time}</span>
  `;

  const content = document.createElement("div");
  content.className = "post-content";
  content.innerHTML = formattedContent;

  postEl.appendChild(header);
  postEl.appendChild(content);

  // Reactions
  if (post.doc.reactions && Object.keys(post.doc.reactions).length > 0) {
    const reactionsEl = document.createElement("div");
    reactionsEl.className = "post-reactions";

    for (const [reaction, users] of Object.entries(post.doc.reactions)) {
      if (users && users.length > 0) {
        const btn = document.createElement("button");
        btn.className = "reaction-btn";
        if (users.includes(currentUser!)) {
          btn.classList.add("active");
        }
        btn.innerHTML = `${reaction} <span class="reaction-count">${users.length}</span>`;
        btn.onclick = (): void => {
          toggleReaction(post.path, reaction);
        };
        reactionsEl.appendChild(btn);
      }
    }

    postEl.appendChild(reactionsEl);
  }

  // Reply button
  const actionsEl = document.createElement("div");
  actionsEl.className = "post-actions";
  const replyBtn = document.createElement("button");
  replyBtn.className = "reply-btn";
  replyBtn.textContent = "Reply";
  replyBtn.onclick = (): void => {
    showReplyInput(post.path, post.doc);
  };
  actionsEl.appendChild(replyBtn);

  // Reaction buttons
  for (const [emoji, code] of Object.entries(emojiMap)) {
    const btn = document.createElement("button");
    btn.className = "reaction-btn";
    btn.textContent = emoji;
    btn.onclick = (): void => {
      addReaction(post.path, emoji);
    };
    actionsEl.appendChild(btn);
  }

  postEl.appendChild(actionsEl);

  // Replies
  const replies = allPosts.filter(
    (p) => p.doc.parent && p.doc.parent.includes(post.path)
  );

  if (replies.length > 0) {
    const repliesEl = document.createElement("div");
    repliesEl.className = "replies";

    for (const reply of replies) {
      const replyEl = document.createElement("div");
      replyEl.className = "reply";
      replyEl.setAttribute("data-path", reply.path);

      const replyAuthor = extractAuthorFromPath(reply.path);
      const replyContent = formatContent(reply.doc.msg);

      replyEl.innerHTML = `
        <div class="post-header">
          <span class="post-author">${escapeHtml(replyAuthor)}</span>
          <span class="post-time">${new Date().toLocaleTimeString()}</span>
        </div>
        <div class="post-content">${replyContent}</div>
      `;

      // Reactions on replies
      if (reply.doc.reactions && Object.keys(reply.doc.reactions).length > 0) {
        const reactionsEl = document.createElement("div");
        reactionsEl.className = "post-reactions";

        for (const [reaction, users] of Object.entries(reply.doc.reactions)) {
          if (users && users.length > 0) {
            const btn = document.createElement("button");
            btn.className = "reaction-btn";
            if (users.includes(currentUser!)) {
              btn.classList.add("active");
            }
            btn.innerHTML = `${reaction} <span class="reaction-count">${users.length}</span>`;
            btn.onclick = (): void => {
              toggleReaction(reply.path, reaction);
            };
            reactionsEl.appendChild(btn);
          }
        }

        replyEl.appendChild(reactionsEl);
      }

      repliesEl.appendChild(replyEl);
    }

    postEl.appendChild(repliesEl);
  }

  postsContainer.appendChild(postEl);
}

function showReplyInput(parentPath: string, parentPost: Post): void {
  const postEl = document.querySelector(`[data-path="${parentPath}"]`);
  if (!postEl) return;

  // Remove existing reply input if present
  const existingInput = postEl.querySelector(".reply-input-area");
  if (existingInput) {
    existingInput.remove();
    return;
  }

  const replyInputArea = document.createElement("div");
  replyInputArea.className = "reply-input-area";

  const textarea = document.createElement("textarea");
  textarea.className = "reply-input";
  textarea.placeholder = "Type your reply...";
  textarea.rows = 2;

  const sendBtn = document.createElement("button");
  sendBtn.className = "send-reply-btn";
  sendBtn.textContent = "Send Reply";

  sendBtn.onclick = async (): Promise<void> => {
    const replyText = textarea.value.trim();
    if (!replyText) return;

    if (!currentWorkspace || !currentChannel) return;

    const success = await createPost(
      currentWorkspace,
      currentChannel,
      replyText,
      parentPath
    );

    if (success) {
      await displayPosts();
    } else {
      showError("Failed to create reply");
    }
  };

  replyInputArea.appendChild(textarea);
  replyInputArea.appendChild(sendBtn);
  postEl.appendChild(replyInputArea);

  textarea.focus();
}

async function addReaction(postPath: string, reaction: string): Promise<void> {
  if (!currentUser) return;

  const response = await apiCall("GET", `${DB_PATH}${postPath}`);
  if (!response.ok) return;

  const post = (await response.json()) as Post;
  const reactions = post.reactions || {};

  if (!reactions[reaction]) {
    reactions[reaction] = [];
  }

  const users = reactions[reaction];
  const userIndex = users.indexOf(currentUser);

  if (userIndex >= 0) {
    users.splice(userIndex, 1);
  } else {
    users.push(currentUser);
  }

  const success = await updatePostReactions(postPath, reactions);
  if (success) {
    await displayPosts();
  }
}

async function toggleReaction(
  postPath: string,
  reaction: string
): Promise<void> {
  await addReaction(postPath, reaction);
}

function formatContent(text: string): string {
  // Escape HTML first
  let result = escapeHtml(text);

  // Replace line breaks
  result = result.replace(/\n/g, "<br>");

  // Replace markdown formatting: **bold**, *italic*, [text](url), :emoji:
  // Bold: **text** -> <strong>text</strong>
  result = result.replace(/\*\*([^*]+?)\*\*/g, "<strong>$1</strong>");

  // Italic: *text* -> <em>text</em>
  result = result.replace(/\*([^*]+?)\*/g, "<em>$1</em>");

  // Links: [text](url) -> <a href="url">text</a>
  result = result.replace(
    /\[([^\]]+?)\]\(([^)]+?)\)/g,
    '<a href="$2" target="_blank">$1</a>'
  );

  // Emoji: :emoji: -> emoji character
  for (const [code, emoji] of Object.entries(emojiMap)) {
    result = result.replace(new RegExp(code.replace(/:/g, "\\:"), "g"), emoji);
  }

  return result;
}

function escapeHtml(text: string): string {
  const map: Record<string, string> = {
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    '"': "&quot;",
    "'": "&#039;",
  };
  return text.replace(/[&<>"']/g, (c) => map[c]);
}

function extractAuthorFromPath(path: string): string {
  const parts = path.split("/");
  if (parts.length > 0) {
    return decodeURIComponent(parts[parts.length - 1]);
  }
  return "Unknown";
}

