    const confirmed = confirm(
      `Are you sure you want to delete "${currentChannel}"?`
    );
    if (!confirmed) return;

    const success = await deleteChannel(currentWorkspace, currentChannel);
    if (success) {
      currentChannel = null;
      channelView.style.display = "none";
      noChannelSelected.style.display = "block";
      await refreshChannelList();
    } else {
      showError("Failed to delete channel");
    }
  });

  sendPostBtn.addEventListener("click", async () => {
    if (!currentWorkspace || !currentChannel) return;

    const text = postInput.value.trim();
    if (!text) return;

    const success = await createPost(currentWorkspace, currentChannel, text);
    if (success) {
      postInput.value = "";
      await displayPosts();
    } else {
      showError("Failed to create post");
